/**
 * Enforces the RecordRTC-only restriction on textless forums (AMD build).
 *
 * @module     local_textless_forum/textless
 * @copyright  2026 Adam Jenkins <adam@wisecat.net>
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define('local_textless_forum/textless', ['core/templates', 'core/str'], function(Templates, Str) {

    var SELECTORS = {
        messageTextarea: 'textarea[name="message[text]"]',
        messageFormat: '[name="message[format]"]',
        messageItemid: 'input[name="message[itemid]"]',
        replyButton: '[data-action="create-inpage-reply"], a[data-action="collapsible-link"][data-post-id]',
        felement: '.felement',
        recorder: '[data-region="textless-recorder"]',
        status: '[data-region="status"]',
        limitInfo: '[data-region="limit-info"]',
        countdown: '[data-region="countdown"]',
        previewWrapper: '[data-region="preview-wrapper"]',
        preview: '[data-region="preview"]',
        playback: '[data-region="playback"]',
        recordAudio: '[data-action="record-audio"]',
        recordVideo: '[data-action="record-video"]',
        stop: '[data-action="stop"]',
        rerecord: '[data-action="rerecord"]'
    };

    /**
     * Pick a sensible file extension for the recorded MIME type.
     *
     * @param {String} mime The MIME type reported by the recorder.
     * @returns {String} A file extension without the leading dot.
     */
    var extensionForMime = function(mime) {
        if (!mime) {
            return 'webm';
        }
        if (mime.indexOf('mp4') !== -1) {
            return 'mp4';
        }
        if (mime.indexOf('ogg') !== -1) {
            return 'ogg';
        }
        return 'webm';
    };

    /**
     * Format a number of seconds as a "minutes:seconds" string for display.
     *
     * @param {Number} totalSeconds The duration in seconds.
     * @returns {String} The duration formatted as M:SS.
     */
    var formatDuration = function(totalSeconds) {
        var minutes = Math.floor(totalSeconds / 60);
        var seconds = Math.floor(totalSeconds % 60);
        return minutes + ':' + (seconds < 10 ? '0' : '') + seconds;
    };

    /**
     * Controls a single message editor once it has been locked down.
     *
     * @param {HTMLElement} recorder The rendered recorder container.
     * @param {HTMLTextAreaElement} textarea The hidden message textarea.
     * @param {HTMLFormElement} form The owning form.
     * @param {Object} config The init configuration (contextid, mode).
     */
    var Recorder = function(recorder, textarea, form, config) {
        this.recorder = recorder;
        this.textarea = textarea;
        this.form = form;
        this.config = config;
        this.mediaRecorder = null;
        this.stream = null;
        this.chunks = [];
        this.mediaType = null;
        this.embed = '';
        this.autoStopTimer = null;
        this.autoStopped = false;
        this.countdownTimer = null;
        this.countdownLabel = '';
        this.recordingEndsAt = 0;

        this.statusEl = recorder.querySelector(SELECTORS.status);
        this.limitInfo = recorder.querySelector(SELECTORS.limitInfo);
        this.countdown = recorder.querySelector(SELECTORS.countdown);
        this.previewWrapper = recorder.querySelector(SELECTORS.previewWrapper);
        this.preview = recorder.querySelector(SELECTORS.preview);
        this.playback = recorder.querySelector(SELECTORS.playback);
        this.audioBtn = recorder.querySelector(SELECTORS.recordAudio);
        this.videoBtn = recorder.querySelector(SELECTORS.recordVideo);
        this.stopBtn = recorder.querySelector(SELECTORS.stop);
        this.rerecordBtn = recorder.querySelector(SELECTORS.rerecord);

        this.registerListeners();
        this.showLimitInfo();
    };

    /**
     * Display the forum's configured maximum recording length, and preload the
     * label used by the live countdown shown while recording. A maxduration of
     * 0 means recordings are not limited, so nothing is shown.
     *
     * @returns {Promise} Resolves once the notice has been populated.
     */
    Recorder.prototype.showLimitInfo = function() {
        var self = this;
        if (!this.config.maxduration || !this.limitInfo) {
            return Promise.resolve();
        }

        return Promise.all([
            Str.getString('maxlength', 'local_textless_forum', formatDuration(this.config.maxduration)),
            Str.getString('timeremaininglabel', 'local_textless_forum')
        ]).then(function(strings) {
            self.limitInfo.textContent = strings[0];
            self.limitInfo.classList.remove('d-none');
            self.countdownLabel = strings[1];
            return;
        });
    };

    Recorder.prototype.registerListeners = function() {
        var self = this;
        if (this.audioBtn) {
            this.audioBtn.addEventListener('click', function() {
                self.start('audio');
            });
        }
        if (this.videoBtn) {
            this.videoBtn.addEventListener('click', function() {
                self.start('video');
            });
        }
        this.stopBtn.addEventListener('click', function() {
            self.stop();
        });
        this.rerecordBtn.addEventListener('click', function() {
            self.reset();
        });

        this.form.addEventListener('submit', function() {
            if (!self.embed) {
                return;
            }
            if (window.tinymce && self.textarea.id) {
                var editor = window.tinymce.get(self.textarea.id);
                if (editor) {
                    editor.remove();
                }
            }
            self.textarea.value = self.embed;
        }, true);
    };

    Recorder.prototype.setStatus = function(key) {
        var self = this;
        return Str.getString(key, 'local_textless_forum').then(function(text) {
            self.statusEl.textContent = text;
            return text;
        });
    };

    Recorder.prototype.setButtons = function(state) {
        var showRecord = state === 'idle';
        if (this.audioBtn) {
            this.audioBtn.classList.toggle('d-none', !showRecord);
        }
        if (this.videoBtn) {
            this.videoBtn.classList.toggle('d-none', !showRecord);
        }
        this.stopBtn.classList.toggle('d-none', state !== 'recording');
        this.rerecordBtn.classList.toggle('d-none', state !== 'recorded');
    };

    Recorder.prototype.start = function(type) {
        var self = this;
        this.mediaType = type;
        this.chunks = [];
        this.clearPlayback();

        var constraints = type === 'video' ? {audio: true, video: true} : {audio: true};

        return navigator.mediaDevices.getUserMedia(constraints).then(function(stream) {
            self.stream = stream;

            if (type === 'video') {
                self.preview.srcObject = stream;
                self.previewWrapper.classList.remove('d-none');
                self.preview.play().catch(function() {
                    return;
                });
            }

            try {
                self.mediaRecorder = new MediaRecorder(stream);
            } catch (e) {
                self.setStatus('errorunsupported');
                self.stopStream();
                return;
            }

            self.mediaRecorder.addEventListener('dataavailable', function(e) {
                if (e.data && e.data.size > 0) {
                    self.chunks.push(e.data);
                }
            });
            self.mediaRecorder.addEventListener('stop', function() {
                self.onStop();
            });
            self.mediaRecorder.start();

            self.scheduleAutoStop();
            self.startCountdown();

            self.setButtons('recording');
            self.setStatus('recording');
            return;
        }).catch(function() {
            self.setStatus('errornopermission');
        });
    };

    /**
     * Schedule the recording to stop automatically once it reaches the
     * forum's configured maximum length. A maxduration of 0 means no limit.
     */
    Recorder.prototype.scheduleAutoStop = function() {
        var self = this;
        if (!this.config.maxduration) {
            return;
        }
        this.autoStopTimer = setTimeout(function() {
            self.autoStopped = true;
            self.stop();
        }, this.config.maxduration * 1000);
    };

    /**
     * Cancel a pending auto-stop, for example when the user stops manually.
     */
    Recorder.prototype.clearAutoStop = function() {
        if (this.autoStopTimer) {
            clearTimeout(this.autoStopTimer);
            this.autoStopTimer = null;
        }
    };

    /**
     * Start showing a live countdown of the time remaining before the
     * recording is stopped automatically. Replaces the static "maximum
     * length" notice for the duration of the recording.
     */
    Recorder.prototype.startCountdown = function() {
        var self = this;
        if (!this.config.maxduration || !this.countdown) {
            return;
        }

        this.recordingEndsAt = Date.now() + (this.config.maxduration * 1000);
        if (this.limitInfo) {
            this.limitInfo.classList.add('d-none');
        }
        this.countdown.classList.remove('d-none');
        this.updateCountdown();
        this.countdownTimer = setInterval(function() {
            self.updateCountdown();
        }, 250);
    };

    /**
     * Refresh the live countdown to reflect the time remaining.
     */
    Recorder.prototype.updateCountdown = function() {
        var remaining = Math.max(0, (this.recordingEndsAt - Date.now()) / 1000);
        this.countdown.textContent = this.countdownLabel + ': ' + formatDuration(remaining);
    };

    /**
     * Stop the live countdown and restore the static "maximum length" notice.
     */
    Recorder.prototype.stopCountdown = function() {
        if (this.countdownTimer) {
            clearInterval(this.countdownTimer);
            this.countdownTimer = null;
        }
        if (!this.countdown) {
            return;
        }
        this.countdown.classList.add('d-none');
        if (this.config.maxduration && this.limitInfo) {
            this.limitInfo.classList.remove('d-none');
        }
    };

    Recorder.prototype.stop = function() {
        this.clearAutoStop();
        this.stopCountdown();
        if (this.mediaRecorder && this.mediaRecorder.state !== 'inactive') {
            this.mediaRecorder.stop();
        }
        this.stopStream();
    };

    Recorder.prototype.stopStream = function() {
        if (this.stream) {
            this.stream.getTracks().forEach(function(track) {
                track.stop();
            });
            this.stream = null;
        }
    };

    Recorder.prototype.onStop = function() {
        var self = this;
        var type = this.mediaType;
        var mime = (this.chunks[0] && this.chunks[0].type)
            || (this.mediaRecorder && this.mediaRecorder.mimeType)
            || (type === 'video' ? 'video/webm' : 'audio/webm');
        var blob = new Blob(this.chunks, {type: mime});

        this.showPlayback(blob, type);
        this.previewWrapper.classList.add('d-none');
        this.preview.srcObject = null;
        this.setButtons('recorded');

        var afterAutoStopNotice = Promise.resolve();
        if (this.autoStopped) {
            this.autoStopped = false;
            afterAutoStopNotice = this.setStatus('recordingstopped');
        }

        return afterAutoStopNotice.then(function() {
            return self.setStatus('uploading');
        }).then(function() {
            return self.upload(blob, type, mime);
        }).then(function(url) {
            self.setEmbed(url, type);
            return self.setStatus('recorded');
        }).catch(function() {
            self.setStatus('erroruploadfailed');
        });
    };

    Recorder.prototype.showPlayback = function(blob, type) {
        this.clearPlayback();
        var player = document.createElement(type === 'video' ? 'video' : 'audio');
        player.controls = true;
        player.src = URL.createObjectURL(blob);
        if (type === 'video') {
            player.classList.add('w-100', 'rounded');
        }
        this.playback.appendChild(player);
        this.playback.classList.remove('d-none');
    };

    Recorder.prototype.clearPlayback = function() {
        this.playback.innerHTML = '';
        this.playback.classList.add('d-none');
    };

    Recorder.prototype.upload = function(blob, type, mime) {
        var itemidEl = this.form.querySelector(SELECTORS.messageItemid);
        var itemid = itemidEl ? itemidEl.value : 0;
        var filename = type + '-' + Date.now() + '.' + extensionForMime(mime);

        var formData = new FormData();
        formData.append('sesskey', M.cfg.sesskey);
        formData.append('itemid', itemid);
        formData.append('contextid', this.config.contextid);
        formData.append('mediatype', type);
        formData.append('recording', blob, filename);

        return fetch(M.cfg.wwwroot + '/local/textless_forum/upload.php', {
            method: 'POST',
            body: formData
        }).then(function(response) {
            return response.json();
        }).then(function(data) {
            if (!data || !data.url) {
                throw new Error('upload failed');
            }
            return data.url;
        });
    };

    Recorder.prototype.setEmbed = function(url, type) {
        var tag = type === 'video' ? 'video' : 'audio';
        this.embed = '<' + tag + ' controls="true"><source src="' + url + '"></' + tag + '>';
        this.textarea.value = this.embed;
        this.textarea.dispatchEvent(new Event('change', {bubbles: true}));
    };

    Recorder.prototype.reset = function() {
        this.clearAutoStop();
        this.stopCountdown();
        this.autoStopped = false;
        this.stopStream();
        this.chunks = [];
        this.embed = '';
        this.mediaType = null;
        this.textarea.value = '';
        this.textarea.dispatchEvent(new Event('change', {bubbles: true}));
        this.clearPlayback();
        this.previewWrapper.classList.add('d-none');
        this.preview.srcObject = null;
        this.setButtons('idle');
        this.setStatus('recorderintro');
    };

    /**
     * Remove any TinyMCE instance attached to the textarea.
     *
     * @param {HTMLTextAreaElement} textarea The message textarea.
     * @returns {Promise} Resolves once TinyMCE has been removed or timed out.
     */
    var destroyTinyMce = function(textarea) {
        return new Promise(function(resolve) {
            var attempts = 0;
            var tryRemove = function() {
                attempts++;
                if (window.tinymce && textarea.id) {
                    var editor = window.tinymce.get(textarea.id);
                    if (editor) {
                        editor.remove();
                        resolve();
                        return;
                    }
                }
                if (attempts > 50) {
                    resolve();
                    return;
                }
                setTimeout(tryRemove, 100);
            };
            tryRemove();
        });
    };

    /**
     * Force the message to be submitted as HTML.
     *
     * @param {HTMLFormElement} form The owning form.
     */
    var forceHtmlFormat = function(form) {
        var formatEl = form.querySelector(SELECTORS.messageFormat);
        if (formatEl) {
            formatEl.value = '1';
        }
    };

    /**
     * Lock down a single message editor and attach a recorder in its place.
     *
     * @param {HTMLTextAreaElement} textarea The message textarea.
     * @param {Object} config The init configuration.
     * @returns {Promise} Resolves once the editor is locked down.
     */
    var lockEditor = function(textarea, config) {
        if (textarea.dataset.textlessReady) {
            return Promise.resolve();
        }
        textarea.dataset.textlessReady = '1';

        var form = textarea.closest('form');
        if (!form) {
            return Promise.resolve();
        }

        forceHtmlFormat(form);

        var felement = textarea.closest(SELECTORS.felement) || textarea.parentElement;
        felement.classList.add('local-textless-forum-locked');
        textarea.readOnly = true;

        destroyTinyMce(textarea);

        var allowAudio = config.mode === 'audio' || config.mode === 'both';
        var allowVideo = config.mode === 'video' || config.mode === 'both';

        return Templates.renderForPromise('local_textless_forum/recorder', {
            allowaudio: allowAudio,
            allowvideo: allowVideo
        }).then(function(rendered) {
            Templates.appendNodeContents(felement, rendered.html, rendered.js);
            var recorder = felement.querySelector(SELECTORS.recorder);
            new Recorder(recorder, textarea, form, config);
            return;
        });
    };

    /**
     * Reroute in-page reply buttons to the advanced (RecordRTC) editor.
     *
     * Different forum discussion layouts trigger the in-page reply form
     * through different controls: the "nested_v2" layout uses a button
     * carrying data-action="create-inpage-reply" and data-href, while the
     * standard layout uses a plain link with data-action="collapsible-link",
     * data-post-id and a normal href (the same data-action also doubles as
     * the in-page form's "Cancel" button, but that one is a <button> with
     * neither attribute, so it is not matched here).
     */
    var interceptReplies = function() {
        if (document.body.dataset.textlessReplies) {
            return;
        }
        document.body.dataset.textlessReplies = '1';

        document.addEventListener('click', function(e) {
            var button = e.target.closest(SELECTORS.replyButton);
            if (!button) {
                return;
            }
            var href = button.getAttribute('data-href') || button.getAttribute('href');
            if (!href) {
                return;
            }
            e.preventDefault();
            e.stopImmediatePropagation();
            window.location.href = href;
        }, true);
    };

    return {
        /**
         * Entry point.
         *
         * @param {Object} config The configuration: {contextid, mode}.
         */
        init: function(config) {
            // Temporary diagnostic — confirms the module loaded and received its config.
            window.console.log('local_textless_forum: enforcing RecordRTC-only editor', config);

            interceptReplies();

            var processAll = function() {
                document.querySelectorAll(SELECTORS.messageTextarea).forEach(function(textarea) {
                    lockEditor(textarea, config);
                });
            };

            processAll();

            var observer = new MutationObserver(function() {
                processAll();
            });
            observer.observe(document.body, {childList: true, subtree: true});
        }
    };
});
